package com.demo.web.dto.Journals;

public class JournalEditRequest { private Integer userId; private String journalIdStr; private String title; private String content; private String decorationsJson; private String backgroundTheme; public JournalEditRequest(Integer userId, String journalIdStr, String title, String content, String decorationsJson, String backgroundTheme) { this.userId = userId; this.journalIdStr = journalIdStr; this.title = title; this.content = content; this.decorationsJson = decorationsJson; this.backgroundTheme = backgroundTheme; } public Integer getUserId() { return userId; } public String getJournalIdStr() { return journalIdStr; } public String getTitle() { return title; } public String getContent() { return content; } public String getDecorationsJson() { return decorationsJson; } public String getBackgroundTheme() { return backgroundTheme; } }
